import{_ as a,o as r,c as p,a2 as o}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"任务币","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"rewards/task-center/task-coins.md","filePath":"zh-CN/rewards/task-center/task-coins.md"}'),e={name:"rewards/task-center/task-coins.md"};function l(i,t,d,n,s,h){return r(),p("div",null,[...t[0]||(t[0]=[o('<h1 id="任务币" tabindex="-1">任务币 <a class="header-anchor" href="#任务币" aria-label="Permalink to &quot;任务币&quot;">​</a></h1><p>任务币是 App 内的虚拟积分货币，用于激励用户参与平台各项功能和活动。</p><p>核心属性：</p><ul><li>不可充值购买，只能通过完成任务、签到、活动等方式获得</li><li>不可提现，不能兑换为现金提取</li><li>有有效期，每笔任务币有独立的到期时间，过期后自动失效，不可找回或延期</li><li>仅限平台内使用，只能在兑换商城消费或在猜涨跌游戏中下注</li></ul><h2 id="获取方式" tabindex="-1">获取方式 <a class="header-anchor" href="#获取方式" aria-label="Permalink to &quot;获取方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>获取途径</th><th>说明</th></tr></thead><tbody><tr><td>完成任务中心各类任务</td><td>包括每日/每周/每月/新手/成长/限时共 6 种任务类型，完成条件后系统自动发放</td></tr><tr><td>完成任务包阶梯奖励</td><td>任务包内完成一定数量的子任务后，按阶梯发放奖励</td></tr><tr><td>每日签到</td><td>每天签到可获得基础任务币，连续/累计签到可获得额外奖励</td></tr><tr><td>猜涨跌游戏预测正确</td><td>预测股票涨跌方向或区间正确后获得任务币奖励</td></tr><tr><td>参与 App 内特定活动</td><td>平台不定期举办的运营活动</td></tr><tr><td>系统补发</td><td>因系统异常或运营补偿，由后台手动补发</td></tr></tbody></table><h2 id="消费方式" tabindex="-1">消费方式 <a class="header-anchor" href="#消费方式" aria-label="Permalink to &quot;消费方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>消费途径</th><th>说明</th></tr></thead><tbody><tr><td>兑换商城兑换商品</td><td>可兑换卡券、实物周边、在线课程、现金、股票份额、App 道具等</td></tr><tr><td>猜涨跌游戏下注</td><td>参与猜涨跌需消耗任务币</td></tr></tbody></table><h2 id="有效期规则" tabindex="-1">有效期规则 <a class="header-anchor" href="#有效期规则" aria-label="Permalink to &quot;有效期规则&quot;">​</a></h2><ul><li>每笔任务币有各自独立的到期时间，不同来源、不同时间获得的任务币到期时间可能不同</li><li>到期后自动从可用余额中扣除，不可找回、不可延期、不可申诉恢复</li><li>在任务币流水/账户页面可查看每笔任务币的到期时间</li><li>建议优先使用即将到期的任务币，定期检查余额和到期情况</li></ul><h2 id="余额查看" tabindex="-1">余额查看 <a class="header-anchor" href="#余额查看" aria-label="Permalink to &quot;余额查看&quot;">​</a></h2><p>任务币余额可在以下位置查看：</p><ol><li>任务中心页面，通常在页面顶部或醒目位置显示当前余额</li><li>兑换商城页面顶部，进入商城时可看到可用余额</li><li>个人账户/资产页面的积分或任务币入口</li></ol><p>各入口显示的余额数值应一致。若出现不一致，请尝试刷新页面或重启 App，若仍有差异请联系客服。</p><h2 id="流水记录" tabindex="-1">流水记录 <a class="header-anchor" href="#流水记录" aria-label="Permalink to &quot;流水记录&quot;">​</a></h2><p>每一笔任务币的获取和消耗都有完整的记录，包括来源/用途、数量、时间、到期时间。进入任务中心，找到&quot;任务币流水&quot;入口即可查看。</p><h2 id="任务币获取与兑换答疑" tabindex="-1">任务币获取与兑换答疑 <a class="header-anchor" href="#任务币获取与兑换答疑" aria-label="Permalink to &quot;任务币获取与兑换答疑&quot;">​</a></h2><p><strong>任务币是什么？和现金有什么区别？</strong></p><p>任务币是 App 内的虚拟积分，不是现金。任务币通过完成任务、签到、活动等方式获得，只能在 App 内的兑换商城使用或在猜涨跌游戏中下注。任务币不可充值购买，也不可提现为现金。</p><p><strong>任务币怎么获得？有哪些途径？</strong></p><p>任务币的获取途径包括：完成任务中心的各类任务（每日/每周/每月/新手/成长/限时）、完成任务包的阶梯奖励、每日签到（连续签到还有额外奖励）、猜涨跌游戏预测正确、参与 App 内特定运营活动、系统补发（运营补偿）。</p><p><strong>任务币可以充值购买吗？</strong></p><p>不可以。任务币只能通过完成任务、签到、活动等方式获得，不支持任何形式的充值购买。</p><p><strong>任务币可以提现吗？</strong></p><p>不可以。任务币是平台内虚拟积分，不支持提现为现金或转账。只能在 App 内兑换商城使用或参与猜涨跌游戏。</p><p><strong>任务币会过期吗？过期了怎么办？</strong></p><p>会过期。每笔任务币有独立的有效期，到期后自动失效。过期的任务币无法找回、无法延期、无法申诉恢复。建议定期查看任务币流水中的到期时间，优先使用即将到期的任务币。</p><p><strong>怎么查看任务币余额？</strong></p><p>可在以下位置查看：任务中心页面、兑换商城页面顶部、个人账户/资产页面的积分或任务币入口。</p><p><strong>怎么查看任务币流水记录？</strong></p><p>进入任务中心，找到&quot;任务币流水&quot;入口，可查看每一笔任务币的获取和消耗记录，包括来源/用途、数量、时间和到期时间。</p><p><strong>为什么我的任务币余额减少了？</strong></p><p>任务币余额减少通常有以下原因：</p><ol><li>过期失效，部分任务币到了有效期自动失效，可在流水记录中确认</li><li>兑换消费，在兑换商城兑换了商品，任务币被扣除</li><li>猜涨跌下注，参与猜涨跌游戏消耗了任务币</li></ol><p>可通过任务币流水记录查看具体的变动明细。若对扣减有疑问，请联系客服并提供账号信息。</p><p><strong>任务币可以转给别人吗？</strong></p><p>不可以。任务币绑定个人账户，不支持转赠、转账或在用户之间流转。</p><p><strong>不同来源的任务币过期时间一样吗？</strong></p><p>不一样。每笔任务币有各自独立的到期时间，不同来源（如签到、完成任务、活动奖励等）获得的任务币到期时间可能不同。请在任务币流水中查看每笔的具体到期时间。</p><p><strong>任务币余额和兑换商城显示的不一致怎么办？</strong></p><p>可能原因包括：页面数据缓存未刷新（尝试下拉刷新或重启 App）、刚完成任务或兑换导致数据同步有短暂延迟、部分任务币刚刚过期被自动扣除。如刷新后仍不一致，请截图两个页面的余额并联系客服处理。</p><p><strong>过期的任务币能找回吗？</strong></p><p>不能。过期的任务币自动失效后无法找回、无法延期、无法通过任何方式恢复。建议定期关注余额和到期时间，及时使用即将过期的任务币。</p><p><strong>任务币可以用来做什么？</strong></p><p>任务币目前有两种使用方式：在兑换商城兑换商品（卡券、实物周边、在线课程、现金、股票份额、App 道具等），以及在猜涨跌游戏中下注参与预测。</p><p><strong>怎样才能获得更多任务币？</strong></p><p>建议：坚持每日签到，争取连续签到额外奖励；关注任务中心的每日/每周/每月任务，周期性完成获取奖励；参与任务包挑战，解锁阶梯奖励；参与猜涨跌游戏，预测正确可获得奖励；关注 App 内不定期推出的限时活动。</p><p><strong>完成任务后任务币多久到账？</strong></p><p>条件达成后系统自动处理奖励，通常较快到账。若完成后超过 24 小时仍未到账，请联系客服并提供账号信息及任务名称。</p><h2 id="任务币使用限制与过期规则" tabindex="-1">任务币使用限制与过期规则 <a class="header-anchor" href="#任务币使用限制与过期规则" aria-label="Permalink to &quot;任务币使用限制与过期规则&quot;">​</a></h2><ul><li>任务币过期失效和兑换消费均不可逆，请谨慎操作</li><li>每笔任务币的到期时间独立，不要将余额视为统一到期</li><li>所有时间判断以系统服务器时间为准，非用户设备本地时间</li><li>任务币是虚拟积分，不具备货币属性，不可充值、不可提现、不可转让</li><li>任务币余额跨设备同步，登录同一账号在不同设备上看到的余额一致</li></ul>',51)])])}const g=a(e,[["render",l]]);export{u as __pageData,g as default};
